<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body{font-family:Arial,Helvetica,sans-serif;margin:20px;}
  form div{margin-bottom:10px;}
  label{display:inline-block;width:80px;}
  input[type=number]{width:100px;}
  select{width:120px;}
  #expenses{border-collapse:collapse; width:100%; margin-top:15px;}
  #expenses th, #expenses td{border:1px solid #ccc;padding:5px;text-align:left;}
  .expense-row{background:#f9f9f9;}
  .exp-del{color:red;background:none;border:none;cursor:pointer;}
  #summary{margin-top:20px;}
  .cat-total{display:inline-block;margin-right:15px;}
  #form-error{color:red;font-weight:bold;}
</style>
</head>
<body>

<h1>Expense Tracker</h1>

<form id="expense-form">
  <div><label for="amount">Amount:</label><input type="number" step="0.01" id="amount" required></div>
  <div><label for="category">Category:</label>
    <select id="category">
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select></div>
  <div><label for="date">Date:</label><input type="date" id="date" required></div>
  <div><label for="note">Note:</label><input type="text" id="note"></div>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<h2>Filters</h2>
<div>
  <label for="filter-category">Category:</label>
  <select id="filter-category">
    <option value="all">All</option>
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="filter-from" style="margin-left:20px;">From:</label>
  <input type="date" id="filter-from">

  <label for="filter-to" style="margin-left:10px;">To:</label>
  <input type="date" id="filter-to">
</div>

<table id="expenses">
  <thead><tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr></thead>
  <tbody></tbody>
</table>

<div id="summary">
  <h3>Total: $<span id="total">0.00</span></h3>
  <div id="cat-summaries"></div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'expenses';
  let expenses = [];

  // Load from localStorage
  function load() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) expenses = JSON.parse(data);
  }

  // Save to localStorage
  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Render expense list
  function renderList() {
    const tbody = document.querySelector('#expenses tbody');
    tbody.innerHTML = '';
    const filtered = getFilteredExpenses();
    filtered.forEach(exp => {
      const tr = document.createElement('tr');
      tr.className = 'expense-row';
      tr.dataset.id = exp.id;
      tr.innerHTML = `
        <td>$${parseFloat(exp.amount).toFixed(2)}</td>
        <td>${exp.category}</td>
        <td>${exp.date}</td>
        <td>${exp.note || ''}</td>
        <td><button class="exp-del">✕</button></td>`;
      tbody.appendChild(tr);
    });
  }

  // Get filtered expenses based on UI filters
  function getFilteredExpenses() {
    const catFilter = document.getElementById('filter-category').value;
    const fromDate = document.getElementById('filter-from').value;
    const toDate = document.getElementById('filter-to').value;

    return expenses.filter(exp => {
      if (catFilter !== 'all' && exp.category !== catFilter) return false;
      if (fromDate && exp.date < fromDate) return false;
      if (toDate && exp.date > toDate) return false;
      return true;
    }).sort((a,b)=>b.id-a.id); // newest first
  }

  // Update totals and per-category summaries
  function updateTotals() {
    const visible = getFilteredExpenses();
    const totalEl = document.getElementById('total');
    const sum = visible.reduce((acc, e)=> acc + parseFloat(e.amount), 0);
    totalEl.textContent = sum.toFixed(2);

    // Per-category
    const catTotals = {};
    visible.forEach(e=> {
      catTotals[e.category] = (catTotals[e.category]||0)+parseFloat(e.amount);
    });
    const container = document.getElementById('cat-summaries');
    container.innerHTML = '';
    ['groceries','transport','bills','fun'].forEach(cat=>{
      const span = document.createElement('span');
      span.className='cat-total';
      span.dataset.cat=cat;
      span.textContent=`${cat}: $${(catTotals[cat]||0).toFixed(2)}`;
      container.appendChild(span);
    });
  }

  // Add new expense
  function addExpense(e){
    e.preventDefault();
    const amount = document.getElementById('amount').value.trim();
    const category = document.getElementById('category').value;
    const date = document.getElementById('date').value;
    const note = document.getElementById('note').value.trim();

    const errorEl = document.getElementById('form-error');
    if (!amount || isNaN(amount) || Number(amount)<=0){
      errorEl.textContent='Please enter a positive numeric amount.';
      return;
    }
    if (!date){errorEl.textContent='Date is required.';return;}
    errorEl.textContent='';
    const newExp = {
      id: Date.now(),
      amount,
      category,
      date,
      note
    };
    expenses.unshift(newExp);
    save();
    renderList();
    updateTotals();
    document.getElementById('amount').value='';
  }

  // Delete expense
  function deleteExpense(e){
    if (!e.target.classList.contains('exp-del')) return;
    const tr = e.target.closest('.expense-row');
    const id = Number(tr.dataset.id);
    expenses = expenses.filter(exp=> exp.id!==id);
    save();
    renderList();
    updateTotals();
  }

  // Filter change handlers
  function onFilterChange(){
    renderList();
    updateTotals();
  }

  // Init
  load();
  renderList();
  updateTotals();

  document.getElementById('expense-form').addEventListener('submit', addExpense);
  document.querySelector('#expenses tbody').addEventListener('click', deleteExpense);
  document.getElementById('filter-category').addEventListener('change', onFilterChange);
  document.getElementById('filter-from').addEventListener('change', onFilterChange);
  document.getElementById('filter-to').addEventListener('change', onFilterChange);
})();
</script>
</body>
</html>
